53	/// sharing the same underlying `std::fs::File` via cloning the handle.
54	/// The write wrapper is flushed on `Drop` (implicit close) so data is not
55	/// lost when `io.close()` drops the `Box<dyn LuaFileHandle>`.
56	enum FsFile {
57	    Read(BufReader<std::fs::File>),
58	    Write(BufWriter<std::fs::File>),
59	    ReadWrite(std::fs::File, Option<u8>),
60	}
61	
62	impl FsFile {
63	    fn open(filename: &[u8], mode: &[u8]) -> io::Result<Self> {
64	        #[cfg(unix)]
65	        let path: std::path::PathBuf = {
66	            use std::os::unix::ffi::OsStrExt;
67	            std::path::PathBuf::from(std::ffi::OsStr::from_bytes(filename))
68	        };
69	        #[cfg(not(unix))]
70	        let path: std::path::PathBuf = {
71	            let s = std::str::from_utf8(filename)
72	                .map_err(|_| io::Error::new(io::ErrorKind::InvalidInput, "filename not valid UTF-8"))?;
73	            std::path::PathBuf::from(s)
74	        };
75	
76	        let first = mode.first().copied().unwrap_or(b'r');
77	        let update = mode.get(1).copied() == Some(b'+');
78	
79	        if first != b'r' {
80	            if let Some(parent) = path.parent() {
81	                if !parent.as_os_str().is_empty() {
82	                    let _ = std::fs::create_dir_all(parent);
83	                }
84	            }
85	        }
86	
87	        match (first, update) {
88	            (b'r', false) => {
89	                let f = std::fs::File::open(&path)?;
90	                Ok(FsFile::Read(BufReader::new(f)))
91	            }
92	            (b'w', false) => {
93	                let f = std::fs::File::create(&path)?;
94	                Ok(FsFile::Write(BufWriter::new(f)))
95	            }
96	            (b'a', false) => {
97	                let mut f = std::fs::OpenOptions::new().append(true).create(true).open(&path)?;
98	                f.seek(SeekFrom::End(0))?;
99	                Ok(FsFile::Write(BufWriter::new(f)))
100	            }
101	            _ => {
102	                let f = std::fs::OpenOptions::new()
103	                    .read(true)
104	                    .write(true)
105	                    .create(first == b'w' || first == b'a')
106	                    .truncate(first == b'w')
107	                    .append(first == b'a')
108	                    .open(&path)?;
109	                Ok(FsFile::ReadWrite(f, None))
110	            }
111	        }
112	    }
113	}
114	
115	impl LuaFileHandle for FsFile {
116	    fn read_byte(&mut self) -> i32 {
117	        match self {
118	            FsFile::Read(r) => {
119	                let mut buf = [0u8; 1];
120	                match r.read(&mut buf) {
121	                    Ok(1) => buf[0] as i32,
122	                    _ => -1,
123	                }
124	            }
125	            FsFile::ReadWrite(f, pushback) => {
126	                if let Some(b) = pushback.take() {
127	                    return b as i32;
128	                }
129	                let mut buf = [0u8; 1];
130	                match f.read(&mut buf) {
131	                    Ok(1) => buf[0] as i32,
132	                    _ => -1,
133	                }
134	            }
135	            FsFile::Write(_) => -1,
136	        }
137	    }
138	
139	    fn unread_byte(&mut self, byte: i32) {
140	        match self {
141	            FsFile::Read(r) => {
142	                if byte >= 0 {
143	                    let _ = r.seek_relative(-1);
144	                }
145	            }
146	            FsFile::ReadWrite(_, pushback) => {
147	                if byte >= 0 {
148	                    *pushback = Some(byte as u8);
149	                }
150	            }
151	            FsFile::Write(_) => {}
152	        }
153	    }
154	
155	    fn write_bytes(&mut self, data: &[u8]) -> io::Result<usize> {
156	        match self {
157	            FsFile::Write(w) => w.write(data),
158	            FsFile::ReadWrite(f, _) => f.write(data),
159	            FsFile::Read(_) => Err(io::Error::new(io::ErrorKind::PermissionDenied, "file not open for writing")),
160	        }
161	    }
162	
163	    fn flush(&mut self) -> io::Result<()> {
164	        match self {
165	            FsFile::Write(w) => w.flush(),
166	            FsFile::ReadWrite(f, _) => f.flush(),
167	            FsFile::Read(_) => Ok(()),
168	        }
169	    }
170	
171	    fn seek(&mut self, pos: SeekFrom) -> io::Result<u64> {
172	        match self {
173	            FsFile::Read(r) => r.seek(pos),
174	            FsFile::Write(w) => w.seek(pos),
175	            FsFile::ReadWrite(f, _) => f.seek(pos),
176	        }
177	    }
178	
179	    fn tell(&mut self) -> io::Result<u64> {
180	        self.seek(SeekFrom::Current(0))
181	    }
182	
183	    fn clear_error(&mut self) {}
184	
185	    fn has_error(&self) -> bool { false }
186	}
187	
188	impl Drop for FsFile {
189	    fn drop(&mut self) {
190	        if let FsFile::Write(w) = self {
191	            let _ = w.flush();
192	        }
193	    }
194	}
195	
196	fn file_remove_hook(filename: &[u8]) -> Result<(), LuaError> {
197	    #[cfg(unix)]
198	    let path: std::path::PathBuf = {
199	        use std::os::unix::ffi::OsStrExt;
200	        std::path::PathBuf::from(std::ffi::OsStr::from_bytes(filename))
201	    };
202	    #[cfg(not(unix))]
203	    let path: std::path::PathBuf = {
204	        let s = std::str::from_utf8(filename).map_err(|_| {
205	            LuaError::runtime(format_args!("filename is not valid UTF-8"))
206	        })?;
207	        std::path::PathBuf::from(s)
208	    };
209	    std::fs::remove_file(&path)
210	        .or_else(|_| std::fs::remove_dir(&path))
211	        .map_err(|err| {
212	            LuaError::runtime(format_args!(
213	                "cannot remove '{}': {}",
214	                String::from_utf8_lossy(filename),
215	                err
216	            ))
217	        })
218	}
219	
220	fn file_rename_hook(from: &[u8], to: &[u8]) -> Result<(), LuaError> {
221	    fn to_path(bytes: &[u8]) -> Result<std::path::PathBuf, LuaError> {
222	        #[cfg(unix)]
223	        {
224	            use std::os::unix::ffi::OsStrExt;
225	            Ok(std::path::PathBuf::from(std::ffi::OsStr::from_bytes(bytes)))
226	        }
227	        #[cfg(not(unix))]
228	        {
229	            let s = std::str::from_utf8(bytes).map_err(|_| {
230	                LuaError::runtime(format_args!("filename is not valid UTF-8"))
231	            })?;
232	            Ok(std::path::PathBuf::from(s))
233	        }
234	    }
235	    let from_path = to_path(from)?;
236	    let to_path_buf = to_path(to)?;
237	    std::fs::rename(&from_path, &to_path_buf).map_err(|err| {
238	        LuaError::runtime(format_args!(
239	            "cannot rename '{}' to '{}': {}",
240	            String::from_utf8_lossy(from),
241	            String::from_utf8_lossy(to),
242	            err
243	        ))
244	    })
245	}
246	
247	fn file_open_hook(filename: &[u8], mode: &[u8]) -> Result<Box<dyn LuaFileHandle>, LuaError> {
248	    FsFile::open(filename, mode).map(|f| Box::new(f) as Box<dyn LuaFileHandle>).map_err(|err| {
249	        LuaError::runtime(format_args!(
250	            "cannot open '{}': {}",
251	            String::from_utf8_lossy(filename),
252	            err
253	        ))
254	    })
255	}
256	
257	// ─── Dynamic library backend (Phase D-3.5) ────────────────────────────────────
258	//
259	// `lua-stdlib` cannot use `libloading` because it forbids `unsafe`. The CLI
260	// owns a per-process registry of loaded libraries and exposes it to
261	// `package.loadlib` via three function-pointer hooks on `GlobalState`. The
262	// registry is a `thread_local!` because `lua-rs` is single-threaded by
263	// construction; `libloading::Library` is not `Sync`. Libraries are leaked
264	// for the lifetime of the process so any function pointer resolved from
265	// them stays valid — that's `libloading`'s safety model.
266	
267	thread_local! {
268	    static DYNLIB_REGISTRY: std::cell::RefCell<Vec<libloading::Library>> =
269	        const { std::cell::RefCell::new(Vec::new()) };
270	}
271	
272	fn path_from_bytes(path: &[u8]) -> Result<std::path::PathBuf, LuaError> {
273	    #[cfg(unix)]
274	    {
275	        use std::os::unix::ffi::OsStrExt;
276	        Ok(std::path::PathBuf::from(std::ffi::OsStr::from_bytes(path)))
277	    }
278	    #[cfg(not(unix))]
279	    {
280	        let s = std::str::from_utf8(path).map_err(|_| {
281	            LuaError::runtime(format_args!("library path is not valid UTF-8"))
282	        })?;
283	        Ok(std::path::PathBuf::from(s))
284	    }
285	}
286	
287	/// `dynlib_load_hook` backend. Loads the library via `libloading` and stashes
288	/// it in the per-thread registry; the returned [`DynLibId`] is the
289	/// registry-vector index, which keeps the library alive until process exit.
290	///
291	/// PORT NOTE: a missing path is reported as `LuaError::File`, which
292	/// `lua-stdlib`'s `package.loadlib` maps to the `"absent"` failure tag (the
293	/// `lua-rs` build behaves like C-Lua's no-dlfcn fallback for plain file-not-
294	/// found, and like POSIX/Windows dlopen for every other open failure).
295	fn dynlib_load(
296	    _state: &mut LuaState,
297	    path: &[u8],
298	    _see_global: bool,
299	) -> Result<DynLibId, LuaError> {
300	    let p = path_from_bytes(path)?;
301	    if !p.exists() {
302	        return Err(LuaError::File);
303	    }
304	    // SAFETY: `libloading::Library::new` executes the dynamic linker, which
305	    // may run arbitrary initializer code in the loaded library. We trust the
306	    // operator-supplied path; this is the same trust model as stock Lua's
307	    // `package.loadlib`. We never call any symbol from the library through
308	    // an unchecked ABI: only `DynamicSymbol::RustNative` is invoked, and
309	    // those must match our Rust function-pointer ABI exactly. Libraries are
310	    // stored in `DYNLIB_REGISTRY` and never unloaded mid-state, so symbol
311	    // pointers resolved later stay valid for as long as the state can call
312	    // them.
313	    let lib = unsafe { libloading::Library::new(&p) }.map_err(|err| {
314	        LuaError::runtime(format_args!(
315	            "cannot load '{}': {}",
316	            String::from_utf8_lossy(path),
317	            err
318	        ))
319	    })?;
320	    let id = DYNLIB_REGISTRY.with(|reg| {
321	        let mut v = reg.borrow_mut();
322	        let idx = v.len() as u64;
323	        v.push(lib);
324	        idx
325	    });
326	    Ok(DynLibId(id))
327	}
328	
329	/// Conservative heuristic: stock Lua C ABI module entry points are named
330	/// `luaopen_<name>` and take a `lua_State *` followed by a single return.
331	/// Without a way to inspect the symbol's signature at run time, we treat any
332	/// symbol whose name starts with `luaopen_` as a C-ABI symbol and refuse it
333	/// with the "ABI not supported" message; everything else is treated as a
334	/// Rust-native entry compatible with `fn(&mut LuaState) -> Result<usize,
335	/// LuaError>`.
336	fn looks_like_c_abi(sym: &[u8]) -> bool {
337	    sym.starts_with(b"luaopen_")
338	}
339	
340	/// `dynlib_symbol_hook` backend. Resolves `symbol` in the library identified
341	/// by `handle`; returns `RustNative` for non-`luaopen_*` symbols and
342	/// `LuaCAbi` (a null pointer placeholder) for `luaopen_*` symbols so
343	/// `package.loadlib` can refuse them with a clear `"init"` error.
344	fn dynlib_symbol(
345	    _state: &mut LuaState,
346	    handle: DynLibId,
347	    symbol: &[u8],
348	) -> Result<DynamicSymbol, LuaError> {
349	    let idx = handle.0 as usize;
350	    DYNLIB_REGISTRY.with(|reg| {
351	        let v = reg.borrow();
352	        let lib = v.get(idx).ok_or_else(|| {
353	            LuaError::runtime(format_args!("invalid dynlib handle {}", idx))
354	        })?;
355	
356	        if looks_like_c_abi(symbol) {
357	            // SAFETY: We only resolve the symbol address; we never call
358	            // through this pointer. The `DynamicSymbol::LuaCAbi` variant is
359	            // a placeholder so `package.loadlib` can report an "init"
360	            // failure with the unsupported-ABI message. The library outlives
361	            // the pointer because `DYNLIB_REGISTRY` retains it for the
362	            // process lifetime.
363	            let resolved: Result<libloading::Symbol<unsafe extern "C" fn()>, _> =
364	                unsafe { lib.get(symbol) };
365	            return match resolved {
366	                Ok(_) => Ok(DynamicSymbol::LuaCAbi(std::ptr::null())),
367	                Err(err) => Err(LuaError::runtime(format_args!(
368	                    "cannot find symbol '{}': {}",
369	                    String::from_utf8_lossy(symbol),
370	                    err
371	                ))),
372	            };
373	        }
374	
375	        type RustNativeFn = fn(&mut LuaState) -> Result<usize, LuaError>;
376	        // SAFETY: We assume the loaded library was built against this build's
377	        // Rust-native module ABI: it exports `symbol` as a function pointer
378	        // with signature `fn(&mut LuaState) -> Result<usize, LuaError>`.
379	        // Verified by convention (operator-supplied path + opt-in `_rs`
380	        // suffix); calling a symbol with the wrong signature is undefined
381	        // behaviour and the operator's responsibility. The library outlives
382	        // the function pointer (kept alive in `DYNLIB_REGISTRY` until
383	        // process exit).
384	        let resolved: Result<libloading::Symbol<RustNativeFn>, _> =
385	            unsafe { lib.get(symbol) };
386	        match resolved {
387	            Ok(sym) => Ok(DynamicSymbol::RustNative(*sym)),
388	            Err(err) => Err(LuaError::runtime(format_args!(
389	                "cannot find symbol '{}': {}",
390	                String::from_utf8_lossy(symbol),
391	                err
392	            ))),
393	        }
394	    })
395	}
396	
397	/// `dynlib_unload_hook` backend. No-op: libraries are kept alive for the
398	/// lifetime of the process to honour `libloading`'s safety model (symbol
399	/// pointers must not outlive the library). Closing libraries at state
400	/// shutdown is platform-dependent and best deferred to OS-level cleanup.
401	fn dynlib_unload(_handle: DynLibId) {}
402	
403	fn parser_hook(
404	    state: &mut LuaState,
405	    source: &[u8],
406	    name: &[u8],
407	    firstchar: i32,
408	) -> Result<GcRef<LuaLClosure>, LuaError> {
409	    let proto = lua_parse::parse(
410	        state,
411	        lua_parse::DynData::default(),
412	        source,
413	        name,
414	        firstchar,
415	    )?;
416	    let nupvals = proto.upvalues.len();
417	    let mut upvals = Vec::with_capacity(nupvals);
418	    for _ in 0..nupvals {
419	        upvals.push(std::cell::RefCell::new(GcRef::new(UpVal::closed(LuaValue::Nil))));
420	    }
421	    Ok(GcRef::new(LuaLClosure {
422	        proto: GcRef::new(*proto),
423	        upvals,
424	    }))
425	}
426	
427	const MULTRET: i32 = -1;
428	
429	fn render_lua_error(e: &LuaError) -> String {
430	    match e {
431	        LuaError::Runtime(v) | LuaError::Syntax(v) => match v {
432	            LuaValue::Str(s) => format!("{}: {}", e_tag(e), String::from_utf8_lossy(s.as_bytes())),
433	            other => format!("{}: {:?}", e_tag(e), other),
434	        },
435	        LuaError::Memory | LuaError::Error | LuaError::Yield
436	        | LuaError::File | LuaError::Gc => format!("{}", e_tag(e)),
437	    }
438	}
439	
440	fn e_tag(e: &LuaError) -> &'static str {
441	    match e {
442	        LuaError::Runtime(_) => "Runtime",
443	        LuaError::Syntax(_)  => "Syntax",
444	        LuaError::Memory     => "Memory",
445	        LuaError::Error      => "Error",
446	        LuaError::Yield      => "Yield",
447	        LuaError::File       => "File",
448	        LuaError::Gc         => "Gc",
449	    }
450	}
451	
452	#[cfg(unix)]
453	fn os_str_bytes(s: &std::ffi::OsString) -> Vec<u8> {
454	    use std::os::unix::ffi::OsStrExt;
455	    s.as_bytes().to_vec()
456	}
457	#[cfg(not(unix))]
458	fn os_str_bytes(s: &std::ffi::OsString) -> Vec<u8> {
459	    s.to_string_lossy().into_owned().into_bytes()
460	}
461	
462	fn main() -> ExitCode {
463	    let args_os: Vec<std::ffi::OsString> = std::env::args_os().collect();
464	    if args_os.len() < 2 {
465	        let prog = args_os
466	            .first()
467	            .map(|s| s.to_string_lossy().into_owned())
468	            .unwrap_or_else(|| "lua-rs".to_string());
469	        eprintln!("usage: {prog} <script.lua | -e 'source'>");
470	        eprintln!("examples:");
471	        eprintln!("  {prog} script.lua");
472	        eprintln!("  {prog} -e 'print(\"hello\")'");
473	        return ExitCode::from(2);
474	    }
475	
476	    let (source, chunkname): (Vec<u8>, Vec<u8>) = if args_os[1] == "-e" {
477	        if args_os.len() < 3 {
478	            eprintln!("-e requires an argument");
479	            return ExitCode::from(2);
480	        }
481	        (os_str_bytes(&args_os[2]), b"=stdin".to_vec())
482	    } else {
483	        let path = std::path::Path::new(&args_os[1]);
484	        if path.is_file() {
485	            match std::fs::read(path) {
486	                Ok(bytes) => {
487	                    let mut name = vec![b'@'];
488	                    name.extend_from_slice(&os_str_bytes(&args_os[1]));
489	                    (bytes, name)
490	                }
491	                Err(e) => {
492	                    eprintln!("cannot read {}: {}", path.display(), e);
493	                    return ExitCode::from(2);
494	                }
495	            }
496	        } else {
497	            (os_str_bytes(&args_os[1]), b"=stdin".to_vec())
498	        }
499	    };
500	
501	    let verbose = std::env::var("LUA_RS_VERBOSE").is_ok();
502	    macro_rules! step { ($($t:tt)*) => { if verbose { eprintln!($($t)*); } }; }
503	
504	    step!("[1/4] Creating LuaState...");
505	    let result = catch_unwind(AssertUnwindSafe(|| {
506	        let mut state = new_state().ok_or("new_state returned None")?;
507	        state.global_mut().parser_hook = Some(parser_hook);
508	        state.global_mut().file_loader_hook = Some(file_loader_hook);
509	        state.global_mut().file_open_hook = Some(file_open_hook);
510	        state.global_mut().file_remove_hook = Some(file_remove_hook);
511	        state.global_mut().file_rename_hook = Some(file_rename_hook);
512	        state.global_mut().dynlib_load_hook = Some(dynlib_load);
513	        state.global_mut().dynlib_symbol_hook = Some(dynlib_symbol);
514	        state.global_mut().dynlib_unload_hook = Some(dynlib_unload);
515	
516	        step!("[2/4] Opening standard library...");
517	        open_libs(&mut state).map_err(|e| format!("open_libs failed: {}", render_lua_error(&e)))?;
518	
519	        step!("[3/4] Loading source (parse + compile)...");
520	        let status = load_buffer(&mut state, &source, &chunkname)
521	            .map_err(|e| format!("load_buffer failed: {}", render_lua_error(&e)))?;
522	        if status != 0 {
523	            let msg = match to_lua_string(&mut state, -1) {
524	                Ok(Some(s)) => String::from_utf8_lossy(s.as_bytes()).into_owned(),
525	                _ => "(no error message on stack)".to_string(),
526	            };
527	            return Err(format!(
528	                "Syntax: {} (load_string status={})",
529	                msg, status
530	            ));
531	        }
532	
533	        step!("[4/4] Executing chunk...");
534	        let final_status = pcall_k(&mut state, 0, MULTRET, 0, 0, None)
535	            .map_err(|e| format!("pcall_k failed: {}", render_lua_error(&e)))?;
536	
537	        Ok::<_, String>(final_status)
538	    }));
539	
540	    match result {
541	        Ok(Ok(status)) => {
542	            if verbose {
543	                eprintln!("[ok] execution completed, status={:?}", status);
544	            }
545	            let _ = status;
546	            ExitCode::SUCCESS
547	        }
548	        Ok(Err(msg)) => {
549	            eprintln!("lua: {}", msg);
550	            ExitCode::from(1)
551	        }
552	        Err(panic) => {
553	            let msg = if let Some(s) = panic.downcast_ref::<String>() {
554	                s.clone()
555	            } else if let Some(s) = panic.downcast_ref::<&str>() {
556	                s.to_string()
557	            } else {
558	                "(non-string panic payload)".to_string()
559	            };
560	            eprintln!("[panic] {}", msg);
561	            ExitCode::from(101)
562	        }
563	    }
564	}
565	
566	// ──────────────────────────────────────────────────────────────────────────
567	// PORT STATUS
568	//   source:        (minimal entrypoint; not a port of lua.c — that's Phase F)
569	//   target_crate:  lua-cli
570	//   confidence:    high
571	//   todos:         0
572	//   port_notes:    0
573	//   unsafe_blocks: 3  (libloading-backed dynlib backend, Phase D-3.5;
574	//                      budget counts 4 due to one `unsafe extern "C" fn()`
575	//                      type parameter on `Symbol<...>`).
576	//   notes:         drives new_state → open_libs → load_string → pcall_k.
577	//                  Designed to surface the first todo!() panic on a hello-
578	//                  world program, not to be a complete interpreter. Hosts the
579	//                  libloading-backed implementation of the three
580	//                  dynlib_*_hook hooks on GlobalState (Phase D-3.5); ceiling
581	//                  in harness/unsafe-budgets.toml = 3.
582	// ──────────────────────────────────────────────────────────────────────────
583

