75	/// Retrieves the coroutine thread at stack index 1, raising a type error if
76	/// the argument is absent or not a thread.
77	///
78	/// C: `static lua_State *getco(lua_State *L)`
79	fn get_co(state: &mut LuaState) -> Result<GcRef<lua_types::value::LuaThread>, LuaError> {
80	    let co = state.to_thread(1);
81	    if co.is_none() {
82	        let got = state.arg(1);
83	        return Err(LuaError::type_arg_error(1, "thread", &got));
84	    }
85	    Ok(co.expect("checked above"))
86	}
87	
88	/// Returns one of the `COS_*` status codes describing `co` relative to the
89	/// calling thread `state`. Mirrors `auxstatus` in `lcorolib.c` exactly,
90	/// reading the target coroutine's `status`, call-frame depth, and stack
91	/// top through `GlobalState::threads`.
92	///
93	/// The main thread (id 0) is never stored in the registry, so a value
94	/// pointing at it is always "running" when it is the current thread.
95	/// Phase E-1 cannot resume coroutines, so any registry-resident thread
96	/// is either suspended (initial state, function still on stack) or dead
97	/// (empty stack).
98	///
99	/// C: `static int auxstatus(lua_State *L, lua_State *co)`
100	fn aux_status(state: &mut LuaState, co: &GcRef<lua_types::value::LuaThread>) -> i32 {
101	    let co_id = co.id;
102	    let entry_rc = {
103	        let g = state.global();
104	        if co_id == g.current_thread_id {
105	            return COS_RUN;
106	        }
107	        match g.threads.get(&co_id) {
108	            Some(e) => e.state.clone(),
109	            None => return COS_DEAD,
110	        }
111	    };
112	    let co_state = entry_rc.borrow();
113	    let raw_status = co_state.status;
114	    if raw_status == LuaStatus::Yield as u8 {
115	        return COS_YIELD;
116	    }
117	    if raw_status != LuaStatus::Ok as u8 {
118	        return COS_DEAD;
119	    }
120	    let has_frames = co_state.ci.as_usize() > 0;
121	    if has_frames {
122	        return COS_NORM;
123	    }
124	    let ci_func = co_state.call_info[0].func.0;
125	    let top = co_state.top.0;
126	    let lua_gettop = top as i64 - ci_func as i64 - 1;
127	    if lua_gettop == 0 {
128	        COS_DEAD
129	    } else {
130	        COS_YIELD
131	    }
132	}
133	
134	/// Transfers `narg` arguments from `state` to `co`, resumes the coroutine,
135	/// then transfers results (or error message) back to `state`.
136	///
137	/// Returns the number of result values (≥ 0) on success, or `-1` on error
138	/// with the error object left on top of `state`'s stack.
139	///
140	/// C: `static int auxresume(lua_State *L, lua_State *co, int narg)`
141	fn aux_resume(state: &mut LuaState, co: GcRef<lua_types::value::LuaThread>, narg: i32) -> i32 {
142	    let co_id = co.id;
143	    let entry_rc = {
144	        let g = state.global();
145	        match g.threads.get(&co_id) {
146	            Some(e) => e.state.clone(),
147	            None => {
148	                drop(g);
149	                push_lit_or_nil(state, b"cannot resume dead coroutine");
150	                return -1;
151	            }
152	        }
153	    };
154	    let parent_thread_id = state.global().current_thread_id;
155	    let top_before = state.get_top();
156	    if top_before < narg {
157	        push_lit_or_nil(state, b"not enough arguments to resume");
158	        return -1;
159	    }
160	    let first_arg_idx = top_before - narg + 1;
161	    let args: Vec<LuaValue> = (first_arg_idx..=top_before)
162	        .map(|i| state.value_at(i))
163	        .collect();
164	    lua_vm::api::set_top(state, (top_before - narg) as i32).ok();
165	
166	    let (status, results_or_err): (LuaStatus, Vec<LuaValue>) = {
167	        let mut co_state = entry_rc.borrow_mut();
168	        if co_state.check_stack(narg + 1).is_err() {
169	            drop(co_state);
170	            push_lit_or_nil(state, b"too many arguments to resume");
171	            return -1;
172	        }
173	        for v in args {
174	            co_state.push(v);
175	        }
176	        co_state.global_mut().current_thread_id = co_id;
177	        let mut nres: i32 = 0;
178	        let status = lua_vm::do_::lua_resume(&mut *co_state, None, narg, &mut nres);
179	        co_state.global_mut().current_thread_id = parent_thread_id;
180	        let co_top = co_state.top_idx().0 as i32;
181	        let ci_func = co_state.current_call_info().func.0 as i32;
182	        let count = if status == LuaStatus::Ok || status == LuaStatus::Yield {
183	            nres
184	        } else {
185	            1
186	        };
187	        let start = co_top - count;
188	        let vals: Vec<LuaValue> = (start..co_top)
189	            .map(|i| co_state.get_at(lua_vm::state::StackIdx(i as u32)))
190	            .collect();
191	        let new_co_top = if status == LuaStatus::Ok || status == LuaStatus::Yield {
192	            (co_top - count).max(ci_func + 1)
193	        } else {
194	            ci_func + 1
195	        };
196	        co_state.set_top(lua_vm::state::StackIdx(new_co_top.max(0) as u32));
197	        (status, vals)
198	    };
199	
200	    match status {
201	        LuaStatus::Ok | LuaStatus::Yield => {
202	            if state.check_stack(results_or_err.len() as i32 + 1).is_err() {
203	                push_lit_or_nil(state, b"too many results to resume");
204	                return -1;
205	            }
206	            let n = results_or_err.len();
207	            for v in results_or_err {
208	                state.push(v);
209	            }
210	            n as i32
211	        }
212	        _ => {
213	            for v in results_or_err {
214	                state.push(v);
215	            }
216	            -1
217	        }
218	    }
219	}
220	
221	/// Helper: push a string literal or fall back to Nil on intern failure.
222	fn push_lit_or_nil(state: &mut LuaState, bytes: &[u8]) {
223	    match state.intern_str(bytes) {
224	        Ok(s) => state.push(LuaValue::Str(s)),
225	        Err(_) => state.push(LuaValue::Nil),
226	    }
227	}
228	
229	// ── Public library functions ──────────────────────────────────────────────────
230	
231	/// `coroutine.resume(co [, val1, ...])` — attempt to resume coroutine `co`.
232	///
233	/// On success pushes `true` followed by all values yielded or returned by `co`.
234	/// On failure pushes `false` followed by the error object.
235	///
236	/// C: `static int luaB_coresume(lua_State *L)`
237	pub fn co_resume(state: &mut LuaState) -> Result<usize, LuaError> {
238	    // C: lua_State *co = getco(L);
239	    let co = get_co(state)?;
240	    // C: r = auxresume(L, co, lua_gettop(L) - 1);
241	    // PORT NOTE: lua_gettop returns the argument count; -1 excludes the coroutine
242	    // itself which sits at index 1.
243	    let narg = state.get_top() - 1;
244	    let r = aux_resume(state, co, narg);
245	    if r < 0 {
246	        // C: lua_pushboolean(L, 0); lua_insert(L, -2); return 2;
247	        state.push(LuaValue::Bool(false));
248	        state.insert(-2);
249	        Ok(2)
250	    } else {
251	        // C: lua_pushboolean(L, 1); lua_insert(L, -(r + 1)); return r + 1;
252	        state.push(LuaValue::Bool(true));
253	        state.insert(-(r + 1));
254	        Ok((r + 1) as usize)
255	    }
256	}
257	
258	/// Closure body installed by `coroutine.wrap`. The wrapped coroutine
259	/// thread is stored in upvalue slot 1 as a `LuaValue::Thread`.
260	///
261	/// On call: forwards all args to `aux_resume` on the captured thread. On
262	/// success returns the yielded/returned values; on coroutine error raises
263	/// the error (matching `select(2, assert(resume(co, ...)))` semantics).
264	///
265	/// C: `static int luaB_auxwrap(lua_State *L)`
266	fn aux_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
267	    let up = state.value_at(upvalue_index(1));
268	    let co = match up {
269	        LuaValue::Thread(t) => t,
270	        _ => {
271	            return Err(LuaError::runtime(format_args!(
272	                "coroutine.wrap: upvalue is not a thread"
273	            )))
274	        }
275	    };
276	    let narg = state.get_top();
277	    let r = aux_resume(state, co, narg);
278	    if r < 0 {
279	        let top = state.get_top();
280	        let err_val = state.value_at(top);
281	        Err(LuaError::from_value(err_val))
282	    } else {
283	        Ok(r as usize)
284	    }
285	}
286	
287	/// `coroutine.create(f)` — create a new coroutine that will run function `f`.
288	///
289	/// Pushes the new thread value and returns 1.
290	///
291	/// Phase E-1: allocates a real `LuaState` registered in
292	/// `GlobalState::threads`, with `f` staged on the new thread's stack so
293	/// `coroutine.status` reports `"suspended"`. The full `xmove` from the
294	/// caller's stack arrives in slice 02b; for this slice the body is
295	/// cloned via `value_at(1)`, which has the same net stack effect since
296	/// `lua_newthread` in C also leaves only the thread value on the
297	/// caller's stack.
298	///
299	/// C: `static int luaB_cocreate(lua_State *L)`
300	pub fn co_create(state: &mut LuaState) -> Result<usize, LuaError> {
301	    state.check_arg_type(1, LuaType::Function)?;
302	    let body = state.value_at(1);
303	    let _nl = state.new_thread(Some(body))?;
304	    Ok(1)
305	}
306	
307	/// `coroutine.wrap(f)` — create a coroutine and return a resuming function.
308	///
309	/// The returned function, when called, resumes the coroutine as if by
310	/// `coroutine.resume`, but raises an error rather than returning `false`.
311	///
312	/// C: `static int luaB_cowrap(lua_State *L)`
313	///
314	/// Captures the new coroutine thread as upvalue 1 of `aux_wrap`.
315	pub fn co_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
316	    co_create(state)?;
317	    state.push_cclosure(aux_wrap, 1)?;
318	    Ok(1)
319	}
320	
321	/// `coroutine.yield([...])` — suspend the running coroutine.
322	///
323	/// All arguments are passed back as results of the corresponding `resume`.
324	///
325	/// C: `static int luaB_yield(lua_State *L)`
326	/// → `return lua_yield(L, lua_gettop(L));`
327	/// → `lua_yield(L,n)` is `lua_yieldk(L, n, 0, NULL)` (lua.h:316)
328	pub fn co_yield(state: &mut LuaState) -> Result<usize, LuaError> {
329	    let n = state.get_top();
330	    let r = lua_vm::do_::lua_yieldk(state, n, 0, None)?;
331	    Ok(r as usize)
332	}
333	
334	/// `coroutine.status(co)` — return a string describing `co`'s current status.
335	///
336	/// Returns one of `"running"`, `"dead"`, `"suspended"`, or `"normal"`.
337	///
338	/// C: `static int luaB_costatus(lua_State *L)`
339	pub fn co_status(state: &mut LuaState) -> Result<usize, LuaError> {
340	    // C: lua_State *co = getco(L);
341	    let co = get_co(state)?;
342	    // C: lua_pushstring(L, statname[auxstatus(L, co)]);
343	    let idx = aux_status(state, &co) as usize;
344	    let name: &[u8] = STAT_NAMES[idx];
345	    let interned = state.intern_str(name)?;
346	    state.push(LuaValue::Str(interned));
347	    Ok(1)
348	}
349	
350	/// `coroutine.isyieldable([co])` — test whether a coroutine (default: current)
351	/// is in a yieldable state.
352	///
353	/// C: `static int luaB_yieldable(lua_State *L)`
354	pub fn co_isyieldable(state: &mut LuaState) -> Result<usize, LuaError> {
355	    let is_yieldable = if matches!(state.type_at(1), LuaType::None) {
356	        state.is_yieldable()
357	    } else {
358	        let co = get_co(state)?;
359	        let co_id = co.id;
360	        let entry_rc = {
361	            let g = state.global();
362	            if co_id == g.main_thread_id {
363	                None
364	            } else {
365	                Some(g
366	                    .threads
367	                    .get(&co_id)
368	                    .expect("thread value carries an id that must resolve in GlobalState::threads")
369	                    .state
370	                    .clone())
371	            }
372	        };
373	        match entry_rc {
374	            None => false,
375	            Some(rc) => rc.borrow().is_yieldable(),
376	        }
377	    };
378	    state.push(LuaValue::Bool(is_yieldable));
379	    Ok(1)
380	}
381	
382	/// `coroutine.running()` — return the current coroutine plus a boolean.
383	///
384	/// The boolean is `true` when the current coroutine is the main thread.
385	///
386	/// C: `static int luaB_corunning(lua_State *L)`
387	pub fn co_running(state: &mut LuaState) -> Result<usize, LuaError> {
388	    // C: int ismain = lua_pushthread(L);
389	    // TODO(port): push_thread pushes a Thread value for the current LuaState and
390	    // returns true iff it is the main thread; Phase B wire-up needed.
391	    let is_main = state.push_thread()?;
392	    // C: lua_pushboolean(L, ismain);
393	    state.push(LuaValue::Bool(is_main));
394	    Ok(2)
395	}
396	
397	/// `coroutine.close(co)` — close a dead or suspended coroutine.
398	///
399	/// Phase E-1 skeleton: the running/normal-rejection branch matches the
400	/// final C-Lua behavior and lands here. Closing a suspended/dead
401	/// coroutine requires running to-be-closed variables and resetting the
402	/// thread; that machinery lands in slice 02d. Until then this returns
403	/// an error rather than silently dropping the work.
404	///
405	/// C: `static int luaB_close(lua_State *L)`
406	pub fn co_close(state: &mut LuaState) -> Result<usize, LuaError> {
407	    let co = get_co(state)?;
408	    let status = aux_status(state, &co);
409	    match status {
410	        COS_RUN | COS_NORM => {
411	            let name = if status == COS_RUN { "running" } else { "normal" };
412	            Err(LuaError::runtime(format_args!(
413	                "cannot close a {} coroutine",
414	                name
415	            )))
416	        }
417	        _ => Err(LuaError::runtime(format_args!(
418	            "coroutine.close not yet implemented for suspended/dead coroutines (Phase E-2d)"
419	        ))),
420	    }
421	}
422	
423	// ── Module entry point ────────────────────────────────────────────────────────
424	
425	/// Opens the `coroutine` standard library by pushing a new table containing
426	/// all `coroutine.*` functions.
427	///
428	/// C: `LUAMOD_API int luaopen_coroutine(lua_State *L)` — `LUAMOD_API` → `pub`.
429	pub fn open_coroutine(state: &mut LuaState) -> Result<usize, LuaError> {
430	    // C: luaL_newlib(L, co_funcs);
431	    // TODO(port): state.new_lib(CO_FUNCS) creates a table from the registration
432	    // slice and leaves it on the stack; Phase B wire-up needed.
433	    state.new_lib(CO_FUNCS)?;
434	    Ok(1)
435	}
436	
437	// ──────────────────────────────────────────────────────────────────────────────
438	// PORT STATUS
439	//   source:        src/lcorolib.c  (210 lines, 12 functions)
440	//   target_crate:  lua-stdlib
441	//   confidence:    medium
442	//   todos:         21
443	//   port_notes:    2
444	//   unsafe_blocks: 0
445	//   notes:         All coroutine execution primitives (resume, yield, xmove,
446	//                  new_thread, close_thread) are Phase E stubs that panic.
447	//                  Argument-checking / result-packaging logic is faithfully
448	//                  translated so Phase E can drop in real implementations.
449	//                  The CO_FUNCS table type references lua_CFunction which is
450	//                  resolved in Phase B.  LuaState / GcRef<LuaState> / LuaStatus
451	//                  imports are all deferred to Phase B.
452	// ──────────────────────────────────────────────────────────────────────────────
